import { pipeline } from "node:stream/promises";
import { Readable } from "node:stream";

declare const awslambda: {
  streamifyResponse: (
    handler: (
      event: unknown,
      responseStream: NodeJS.WritableStream,
      context: unknown
    ) => Promise<void>
  ) => (event: unknown, context: unknown) => Promise<void>;
  HttpResponseStream: {
    from: (
      responseStream: NodeJS.WritableStream,
      metadata: ResponseMetadata
    ) => NodeJS.WritableStream;
  };
};

interface ResponseMetadata {
  statusCode: number;
  headers: Record<string, string>;
}

export const lambdaHandler = awslambda.streamifyResponse(
  async (
    event: unknown,
    responseStream: NodeJS.WritableStream,
    _context: unknown
  ): Promise<void> => {
    const metadata: ResponseMetadata = {
      statusCode: 200,
      headers: {
        "Content-Type": "text/event-stream; charset=utf-8",
      },
    };
    responseStream = awslambda.HttpResponseStream.from(
      responseStream,
      metadata
    );
    const readable = Readable.from([
      "DBの内容です\n",
      "2026-03-01T10:00:00+09:00 1件のリクエストがありました\n",
      "2026-03-02T11:00:00+09:00 3件の修正がありました\n",
      "2026-03-03T13:00:00+09:00 1件の削除がありました\n",
    ]);
    await pipeline(readable, responseStream);
  }
);
